#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        int *odd = (int*)malloc(N*sizeof(int));
        int *even = (int*)malloc(N*sizeof(int));
        int oc=0, ec=0, x;
        for(int i=0;i<N;i++){
            scanf("%d",&x);
            if(x&1) odd[oc++]=x; else even[ec++]=x;
        }
        if(oc==0 || ec==0){
            printf("-1\n");
        }else{
            for(int i=0;i<oc;i++) printf("%d ",odd[i]);
            for(int i=0;i<ec;i++) printf("%d%s",even[i], i==ec-1?"":" ");
            printf("\n");
        }
        free(odd); free(even);
    }
    return 0;
}

