#include <bits/stdc++.h>
using namespace std;
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        int N; cin>>N;
        vector<int> odd, even;
        odd.reserve(N); even.reserve(N);
        for(int i=0;i<N;i++){
            int x; cin>>x;
            if(x&1) odd.push_back(x); else even.push_back(x);
        }
        if(odd.empty() || even.empty()){
            cout<<-1<<"\n";
        }else{
            for(size_t i=0;i<odd.size();++i) cout<<odd[i]<<' ';
            for(size_t i=0;i<even.size();++i){
                cout<<even[i];
                if(i+1<even.size()) cout<<' ';
            }
            cout<<"\n";
        }
    }
    return 0;
}

