#!/usr/bin/env python3
import sys
def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        odd = []
        even = []
        for _ in range(N):
            x = int(next(it))
            (odd if x & 1 else even).append(x)
        if not odd or not even:
            out_lines.append('-1')
        else:
            out_lines.append(' '.join(map(str, odd + even)))
    sys.stdout.write('\n'.join(out_lines))
if __name__ == "__main__":
    solve()

